// Lenis
gsap.registerPlugin(ScrollTrigger);

  const lenis = new Lenis({
    lerp: 0.1,
    wheelMultiplier: 0.8,
    smoothWheel: true,
    smoothTouch: true
  });

  lenis.on('scroll', ScrollTrigger.update);

  gsap.ticker.add((time) => {
    lenis.raf(time * 1000);
  });

  gsap.ticker.lagSmoothing(0);

  ScrollTrigger.addEventListener("refresh", () => lenis.resize());
  ScrollTrigger.refresh();

function initDynamicCurrentYear() {  
  const currentYear = new Date().getFullYear();
  const currentYearElements = document.querySelectorAll('[data-current-year]');
  currentYearElements.forEach(currentYearElement => {
    currentYearElement.textContent = currentYear;
  });
}

// Initialize Dynamic Current Year
document.addEventListener('DOMContentLoaded', () => {
  initDynamicCurrentYear();
});

// Swiper
document.addEventListener("DOMContentLoaded", function () {
  
  document.querySelectorAll(".agenda-swiper").forEach(function (slider) {

    const swiperEl = slider.querySelector(".swiper");
    const nextBtn = slider.querySelector(".agenda-next");
    const prevBtn = slider.querySelector(".agenda-prev");

    new Swiper(swiperEl, {
      slidesPerView: 3.5,
      spaceBetween: 16,
      speed: 775,

      navigation: {
        nextEl: nextBtn,
        prevEl: prevBtn,
      },

      breakpoints: {
        0: { slidesPerView: 1.25, spaceBetween: 8 },
        768: { slidesPerView: 2.25, spaceBetween: 12 },
        1200: { slidesPerView: 2.5, spaceBetween: 16 },
        1440: { slidesPerView: 3.25, spaceBetween: 16 },
      },
    });

  });

});

// FAQ
document.addEventListener("click", (e) => {
  const trigger = e.target.closest(".faq_item_inner");
  if (!trigger) return;

  const item = trigger.closest(".faq_item");
  if (!item) return;

  const answer = item.querySelector(".faq_answer_wrapper");
  if (!answer) return;

  const isOpen = item.classList.contains("is-open");

  document.querySelectorAll(".faq_item.is-open").forEach((openItem) => {
    if (openItem === item) return;
    openItem.classList.remove("is-open");
    const openAnswer = openItem.querySelector(".faq_answer_wrapper");
    if (openAnswer) openAnswer.style.maxHeight = "0px";
  });

  if (isOpen) {
    item.classList.remove("is-open");
    answer.style.maxHeight = "0px";
  } else {
    item.classList.add("is-open");
    answer.style.maxHeight = answer.scrollHeight + "px";
  }
});
